curl --header "Authorization: Bearer ${ACCESS_TOKEN}" \
    --header "Accept: application/vnd.atlas.2025-03-12+json" \
    --header "Content-Type: application/json" \
    -X POST "https://cloud.mongodb.com/api/atlas/v2/groups/{groupId}/clusters/{clusterName}/search/indexes" \
    -d '{ "collectionName": "<collection>",
        "database": "<database>",
        "name": "default",
        "type": "search",
        "definition": {
          "mappings": {
            "dynamic": true|false,
            "fields": {
              "<field-name>": {
                "type": "string",
                "analyzer": "<atlas-search-analyzer>",
                "searchAnalyzer": "<atlas-search-analyzer>",
                "indexOptions": "docs|freqs|positions|offsets",
                "store": true|false,
                "ignoreAbove": <integer>,
                "similarity": { "type": "bm25|boolean|stableTfl" },
                "multi": {<string-field-definition>},
                "norms": "include|omit"
              }
            }
          }
        }
    }'

curl --header "Authorization: Bearer ${ACCESS_TOKEN}" \
  --header "Accept: application/vnd.atlas.2025-03-12+json" \
  --header "Content-Type: application/json" \
  -X POST "https://cloud.mongodb.com/api/atlas/v2/groups/{groupId}/clusters/{clusterName}/search/indexes" \
  -d '{ "collectionName": "movies",
        "database": "sample_mflix",
        "name": "default",
        "type": "search",
        "definition": {
          "mappings": { 
            "dynamic": false, 
            "fields": { 
              "title": { 
                "type": "string" 
              } 
            } 
          }
        }
    }'

curl --header "Authorization: Bearer ${ACCESS_TOKEN}" \
  --header "Accept: application/vnd.atlas.2025-03-12+json" \
  --header "Content-Type: application/json" \
  -X POST "https://cloud.mongodb.com/api/atlas/v2/groups/{groupId}/clusters/{clusterName}/search/indexes" \
  -d '{ "collectionName": "movies",
        "database": "sample_mflix",
        "name": "default",
        "type": "search",
        "definition": {
          "mappings": { 
            "dynamic": false, 
            "fields": { 
              "title": { 
                "type": "string",
                "multi": {
                  "english": {
                    "type": "string",
                    "analyzer": "lucene.english"
                  },
                  "french": {
                    "type": "string",
                    "analyzer": "lucene.french"
                  },
                  "stableSimilarity": {
                    "type": "string",
                    "similarity": { "type": "stableTfl" }
                  }
                }
              } 
            }
          }
        }
    }'
